module RefModule(
    input CLK,
    input reset,
    output reg CLK_div
);reg [3:0] unused_counter;

    always @ (posedge CLK or posedge reset) begin
        if (reset) begin
            unused_counter <= 0;
            CLK_div <= 0;
        end
        else begin
            unused_counter <= unused_counter + 1;
            if (unused_counter == 4) begin
                unused_counter <= 0;
                CLK_div <= ~CLK_div;
            end
        end
    end

endmodule
